#nullable enable // autogenerated

using MVZ2.GameContent.Damages;
using MVZ2.GameContent.Models;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Definitions;
using MVZ2Logic.Entities;
using MVZ2Logic.HeldItems;
using MVZ2Logic.Level;
using PVZEngine.Callbacks;
using PVZEngine.Damages;
using PVZEngine.Entities;
using PVZEngine.Level;
using PVZEngine.Definitions;

namespace MVZ2.GameContent.HeldItems
{
    [AutoHeldItemBehaviourDefinition(VanillaHeldItemBehaviourNames.pickaxe)]
    public class PickaxeHeldItemBehaviour : ToEntityHeldItemBehaviour
    {
        public PickaxeHeldItemBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        public override HeldTargetFlag GetHeldTargetMask(LevelEngine level)
        {
            return HeldTargetFlag.Plant | HeldTargetFlag.Obstacle;
        }
        protected override bool CanUseOnEntity(Entity entity)
        {
            if (!entity.ExistsAndAlive() || entity.NoHeldTarget() || entity.CannotDig())
                return false;
            if (entity.Type != EntityTypes.PLANT && entity.Type != EntityTypes.OBSTACLE)
                return false;
            return entity.IsFriendlyEntity() || entity.CanBeKilledByPickaxe();
        }
        protected override void UseOnEntity(Entity entity)
        {
            DamageEffectList effects = new DamageEffectList(VanillaDamageEffects.PICKAXE);
            entity.Die(effects);
            if (entity.Level.IsPickaxeCountLimited())
            {
                entity.Level.AddPickaxeRemainCount(-1);
            }
        }
        public override void GetModelID(LevelEngine level, IHeldItemData data, CallbackResult result)
        {
            result.SetFinalValue(VanillaModelID.pickaxeHeldItem);
        }
    }
}
